 3→import en from "./translations/en.json";
 4→import pl from "./translations/pl.json";
 5→
 6→const resources = {
 7→  en: { translation: en },
 8→  pl: { translation: pl },
 9→};
10→
11→i18n.use(initReactI18next).init({
12→  compatibilityJSON: "v4",
13→  resources,
14→  lng: "en",
15→  fallbackLng: "en",
16→  interpolation: {
17→    escapeValue: false,
18→  },
19→});
