  1→import { parseTags } from "@/lib/utils/recipeValidation";
  2→import { useTranslation } from "@/platform/i18n/useTranslation";
  3→import { useTheme, type Theme } from "@/platform/theme/useTheme";
  4→import { useCallback, useEffect, useRef, useState, type JSX } from "react";
  5→import {
  6→  Pressable,
  7→  StyleSheet,
  8→  Text,
  9→  TextInput,
 10→  View,
 11→  type ViewStyle,
 12→} from "react-native";
 13→
 14→export function TagInput({
 15→  ref,
 16→  tags,
 17→  onChange,
 18→  style,
 19→  onFocus,
 20→  label = "Tags",
 21→  placeholder = "Add tags...",
 22→}: {
 23→  ref?: React.RefObject<TextInput | null>;
 24→  tags: Array<string>;
 25→  onChange: (tags: Array<string>) => void;
 26→  style?: ViewStyle;
 27→  onFocus?: () => void;
 28→  label?: string;
 29→  placeholder?: string;
 30→}): JSX.Element {
 31→  const theme = useTheme();
 32→  const { t } = useTranslation();
 33→  const [inputValue, setInputValue] = useState("");
 34→  const inputRef = useRef<TextInput>(null);
 35→
 36→  useEffect(() => {
 37→    if (ref && inputRef.current) {
 38→      ref.current = inputRef.current;
 39→    }
 40→  }, [ref]);
 41→
 42→  const addTags = useCallback(() => {
 43→    if (inputValue.trim()) {
 44→      const newTags = parseTags(inputValue).filter(
 45→        (tag) => !tags.includes(tag)
 46→      );
 47→
 48→      if (newTags.length > 0) {
 49→        onChange([...tags, ...newTags]);
 50→      }
 51→      setInputValue("");
 52→    }
 53→  }, [inputValue, tags, onChange]);
 54→
 55→  const handleSubmit = useCallback(() => {
 56→    addTags();
 57→    inputRef.current?.blur();
 58→  }, [addTags]);
 59→
 60→  const handleChangeText = useCallback(
 61→    (text: string) => {
 62→      // Check if last character is comma or space
 63→      if (text.endsWith(",") || text.endsWith(" ")) {
 64→        const textWithoutDelimiter = text.slice(0, -1);
 65→        if (textWithoutDelimiter.trim()) {
 66→          const newTags = parseTags(textWithoutDelimiter).filter(
 67→            (tag) => !tags.includes(tag)
 68→          );
 69→
 70→          if (newTags.length > 0) {
 71→            onChange([...tags, ...newTags]);
 72→          }
 73→          setInputValue("");
 74→          return;
 75→        }
 76→      }
 77→      setInputValue(text);
 78→    },
 79→    [tags, onChange]
 80→  );
 81→
 82→  const handleRemoveTag = useCallback(
 83→    (tagToRemove: string) => {
 84→      onChange(tags.filter((tag) => tag !== tagToRemove));
 85→    },
 86→    [tags, onChange]
 87→  );
 88→
 89→  return (
 90→    <View style={[styles.container, style]}>
 91→      <Text style={[styles.label, getThemeColors(theme).label]}>{label}</Text>
 92→      <View
 93→        style={[styles.inlineContainer, getThemeColors(theme).inlineContainer]}
 94→      >
 95→        <TextInput
 96→          accessibilityLabel={label}
 97→          accessibilityHint={placeholder}
 98→          ref={inputRef}
 99→          style={[styles.input, getThemeColors(theme).input]}
100→          value={inputValue}
101→          onChangeText={handleChangeText}
102→          onBlur={addTags}
103→          onSubmitEditing={handleSubmit}
104→          onFocus={onFocus}
105→          returnKeyType="done"
106→          placeholder={placeholder}
107→          placeholderTextColor={getThemeColors(theme).placeholder.color}
108→        />
109→        {tags.map((tag) => (
110→          <Pressable
111→            key={tag}
112→            onPress={() => handleRemoveTag(tag)}
113→            style={[styles.tagPill, getThemeColors(theme).tagPill]}
114→            accessibilityLabel={`${t("accessibility.removeTag")} ${tag}`}
115→            accessibilityRole="button"
116→          >
117→            <Text style={[styles.tagText, getThemeColors(theme).tagText]}>
118→              {tag}
119→            </Text>
120→            <Text style={[styles.removeIcon, getThemeColors(theme).tagText]}>
121→              ×
122→            </Text>
123→          </Pressable>
124→        ))}
125→      </View>
126→    </View>
127→  );
128→}
129→
130→function getThemeColors(theme: Theme) {
131→  const isDark = theme === "dark";
132→
133→  return {
134→    label: {
135→      color: isDark ? "#E5E5E5" : "#1F1F1F",
136→    },
137→    inlineContainer: {
138→      backgroundColor: isDark
139→        ? "rgba(255, 255, 255, 0.1)"
140→        : "rgba(0, 0, 0, 0.05)",
141→      borderColor: isDark ? "rgba(255, 255, 255, 0.2)" : "rgba(0, 0, 0, 0.1)",
142→    },
143→    input: {
144→      color: isDark ? "#FFFFFF" : "#000000",
145→    },
146→    placeholder: {
147→      color: isDark ? "rgba(255, 255, 255, 0.5)" : "rgba(0, 0, 0, 0.4)",
148→    },
149→    tagPill: {
150→      backgroundColor: isDark
151→        ? "rgba(255, 255, 255, 0.15)"
152→        : "rgba(0, 0, 0, 0.08)",
153→    },
154→    tagText: {
155→      color: isDark ? "#FFFFFF" : "#000000",
156→    },
157→  };
158→}
159→
160→const styles = StyleSheet.create({
161→  container: {
162→    gap: 8,
163→  },
164→  label: {
165→    fontSize: 16,
166→    fontWeight: "500",
167→  },
168→  inlineContainer: {
169→    flexDirection: "row",
170→    flexWrap: "wrap",
171→    alignItems: "center",
172→    gap: 8,
173→    borderWidth: 1,
174→    borderRadius: 28,
175→    paddingHorizontal: 16,
176→    paddingVertical: 8,
177→    minHeight: 48,
178→  },
179→  tagPill: {
180→    flexDirection: "row",
181→    alignItems: "center",
182→    gap: 6,
183→    paddingHorizontal: 12,
184→    paddingVertical: 6,
185→    borderRadius: 16,
186→  },
187→  tagText: {
188→    fontSize: 14,
189→  },
190→  removeIcon: {
191→    fontSize: 18,
192→    fontWeight: "bold",
193→  },
194→  input: {
195→    flex: 1,
196→    minWidth: 120,
197→    paddingHorizontal: 4,
198→    paddingVertical: 6,
199→    fontSize: 16,
200→  },
201→});
