  1→import { Alert } from "@/lib/alert";
  2→import { RecipeImageDisplay } from "@/lib/components/atoms/RecipeImageDisplay";
  3→import { ZoomableImage } from "@/lib/components/atoms/ZoomableImage";
  4→import { useImageCoverSize } from "@/lib/hooks/useImageCoverSize";
  5→import { useLocalizedTagLabels } from "@/features/tags/hooks/useLocalizedTagLabels";
  6→import type { RecipeMetadataWrite } from "@/lib/repositories/types";
  7→import type { Recipe } from "@/lib/types/recipe";
  8→import { LiquidGlassButton } from "@/modules/liquid-glass";
  9→import { useTranslation } from "@/platform/i18n/useTranslation";
 10→import { getColors } from "@/platform/theme/glassStyles";
 11→import { useTheme } from "@/platform/theme/useTheme";
 12→import * as Haptics from "expo-haptics";
 13→import { router } from "expo-router";
 14→import { type JSX, useCallback, useRef, useState } from "react";
 15→import {
 16→  KeyboardAvoidingView,
 17→  Platform,
 18→  ScrollView,
 19→  StyleSheet,
 20→  useWindowDimensions,
 21→  View,
 22→} from "react-native";
 23→import { useRecipeForm } from "../hooks/useRecipeForm";
 24→import { MetadataFormFields } from "./MetadataFormFields";
 25→
 26→export function EditRecipeForm({
 27→  recipe,
 28→  onSubmit,
 29→}: {
 30→  recipe: Recipe;
 31→  onSubmit: (metadata: RecipeMetadataWrite) => void;
 32→}): JSX.Element {
 33→  const theme = useTheme();
 34→  const colors = getColors(theme);
 35→  const { t } = useTranslation();
 36→  const scrollViewRef = useRef<ScrollView>(null);
 37→  const { width } = useWindowDimensions();
 38→  const [isZoomed, setIsZoomed] = useState(false);
 39→  const { coverSize, onImageLoad } = useImageCoverSize(width, width);
 40→  const resolvedInitialTags = useLocalizedTagLabels(recipe.metadata.tagIds);
 41→  const { values, handleChange, handleSubmit, isDirty } = useRecipeForm({
 42→    initialValues: {
 43→      title: recipe.metadata.title,
 44→      source: recipe.metadata.source,
 45→      tags: resolvedInitialTags,
 46→      tagIds: recipe.metadata.tagIds,
 47→    },
 48→    onSubmit,
 49→  });
 50→
 51→  const handleBack = useCallback(() => {
 52→    if (Platform.OS !== "web") {
 53→      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
 54→    }
 55→    router.back();
 56→  }, []);
 57→
 58→  const handleDiscard = useCallback(() => {
 59→    if (Platform.OS !== "web") {
 60→      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
 61→    }
 62→    Alert.alert(
 63→      t("recipeForm.discardChanges.title"),
 64→      t("recipeForm.discardChanges.message"),
 65→      [
 66→        { text: t("recipeForm.discardChanges.cancel"), style: "cancel" },
 67→        {
 68→          text: t("recipeForm.discardChanges.discard"),
 69→          style: "destructive",
 70→          onPress: () => {
 71→            if (Platform.OS !== "web") {
 72→              Haptics.notificationAsync(
 73→                Haptics.NotificationFeedbackType.Warning
 74→              );
 75→            }
 76→            router.back();
 77→          },
 78→        },
 79→      ]
 80→    );
 81→  }, [t]);
 82→
 83→  const handleFormSubmit = useCallback(() => {
 84→    if (Platform.OS !== "web") {
 85→      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
 86→    }
 87→    handleSubmit();
 88→  }, [handleSubmit]);
 89→
 90→  return (
 91→    <KeyboardAvoidingView
 92→      style={[styles.container, { backgroundColor: colors.background }]}
 93→      behavior={Platform.OS === "ios" ? "padding" : "height"}
 94→      keyboardVerticalOffset={Platform.OS === "ios" ? 0 : 20}
 95→    >
 96→      <ScrollView
 97→        ref={scrollViewRef}
 98→        contentContainerStyle={styles.scrollContent}
 99→        keyboardShouldPersistTaps="handled"
100→        scrollEnabled={!isZoomed}
101→      >
102→        <View style={styles.imageContainer}>
103→          <ZoomableImage
104→            style={{ width, height: width }}
105→            onZoomChange={setIsZoomed}
106→            maxScale={3}
107→          >
108→            <RecipeImageDisplay
109→              uri={recipe.photoUri}
110→              style={coverSize ?? { width, height: width }}
111→              onLoad={onImageLoad}
112→            />
113→          </ZoomableImage>
114→        </View>
115→
116→        <View style={styles.formContainer}>
117→          <MetadataFormFields
118→            value={values}
119→            onChange={handleChange}
120→            scrollViewRef={scrollViewRef}
121→          />
122→        </View>
123→      </ScrollView>
124→
125→      <View style={styles.bottomBar}>
126→        {isDirty ? (
127→          <LiquidGlassButton
128→            onPress={handleDiscard}
129→            accessibilityLabel={t("accessibility.close")}
130→            systemImage="xmark"
131→          />
132→        ) : (
133→          <LiquidGlassButton
134→            onPress={handleBack}
135→            accessibilityLabel={t("accessibility.back")}
136→            systemImage="chevron.left"
137→          />
138→        )}
139→
140→        <View style={{ flex: 1 }} />
141→
142→        <LiquidGlassButton
143→          onPress={handleFormSubmit}
144→          accessibilityLabel={t("recipeForm.submitEdit")}
145→          systemImage="checkmark"
146→        />
147→      </View>
148→    </KeyboardAvoidingView>
149→  );
150→}
151→
152→const styles = StyleSheet.create({
153→  container: {
154→    flex: 1,
155→  },
156→  scrollContent: {
157→    flexGrow: 1,
158→    paddingBottom: 100,
159→  },
160→  imageContainer: {
161→    position: "relative",
162→    overflow: "hidden",
163→  },
